module select2_5(
    input [4:0] in1,
    input [4:0] in2,
    input choose,
    output reg [4:0] out
);
  wire [4:0] _tap_in1 = in1 & {5{1'b1}};


    always@(in1 or in2 or choose)
    case(choose)
        1'b0: out = in1;
        1'b1: out = in2;
        default: out = 5'b0;
    endcase

endmodule
